    @Override
    @InitializeAdmin
    @Transactional
    public Integer createUpdateApoBedragen(Admin admin, List<ApoBedragDTO> dtos, String actor) {
        Integer hoofdId = null;
        boolean hasChange = false;

        for (ApoBedragDTO dto : dtos) {

            Integer bedragId = dto.getId();

            LocalDateTime ingaveTijdstip = TemporalContext.getInstance().getWerkTijdstip();

            if (bedragId != null) {
                ApoBedrag pojo = apoService.getByIdApoBedrag(admin, bedragId);

                Integer apoHoofdId = pojo.getApoLijn().getApoHoofd().getId();
                if (apoHoofdId != null && hoofdId == null) {
                    hoofdId = apoHoofdId;
                }

                if (dto.getBedrag() == null || BigDecimal.ZERO.compareTo(dto.getBedrag()) == 0) {
                    hasChange = true;
                    // delete existing bedrag
                    apoService.delete(admin, pojo.getApoLijn(), pojo);
                } else if (pojo.getBedrag().getAmount().compareTo(dto.getBedrag()) != 0) {
                    hasChange = true;
                    // update only if the amount is changed...
                    pojo.setRegulTijdstip(ingaveTijdstip);
                    apoService.updateBedrag(admin, pojo);

                    ApoBedrag newPojo = new ApoBedragPO();
                    newPojo.setApoLijn(pojo.getApoLijn());
                    newPojo.setBedrag(new Money(dto.getBedrag()));
                    newPojo.setBedragType(pojo.getBedragType());
                    newPojo.setIngaveTijdstip(ingaveTijdstip);
                    newPojo.setActor(actor);
                    apoService.createBedrag(admin, newPojo);
                }
            } else {
                if (dto.getBedrag() != null && BigDecimal.ZERO.compareTo(dto.getBedrag()) != 0) {
                    hasChange = true;
                    Integer apoHoofdId = checkCreateApoHoofd(admin, dto, actor);
                    if (apoHoofdId != null && hoofdId == null) {
                        hoofdId = apoHoofdId;
                    }
                }
            }

        }

        if (hoofdId == null) {
            log.warn("hoofdId = {}, hoofd id should not be null!", hoofdId);
        } else if (hasChange) {
            createRegulAgendaAPO(admin, hoofdId);
        }

        return hoofdId;
    }

    @Override
    @InitializeAdmin
    @Transactional
    public void createRegulAgendaAPO(Admin admin, Integer hoofdId) {
        ApoHoofd hoofd;
        Opdracht opdracht;
        Persoon persoon;
        try {
            TemporalContext.getInstance().setActualInterval(new Eternity());
            hoofd = apoService.getById(admin, hoofdId, "opdracht{opdrachtSlices, persoon}");
            log.debug("hoofdId = {}, hoofd = {}", hoofdId, hoofd);
            opdracht = hoofd.getOpdracht();
            persoon = opdracht.getPersoon();
        } finally {
            TemporalContext.getInstance().clearActualInterval();
        }

        RegulAgenda agenda = new RegulAgendaPO();
        RegulAgendaPK pk = new RegulAgendaPK();
        pk.setBeginDatum(LocalDateUtil.getInstance().withStartOfMonth(hoofd.getBeginDatum()));
        pk.setEindDatum(LocalDateUtil.getInstance().withEndOfMonth(hoofd.getBeginDatum()));
        pk.setOpdrachtNummer(opdracht.getOpdrachtnr());
        pk.setPersoon(persoon);
        pk.setRegulStatus(Regulkode.WIJZ_APO.getCode());
        agenda.setId(pk);
        agenda.setWerkgever(opdracht.getWerkgever());
        agenda.setBron(BronAgenda.RM_INPUT);

        regulAgendaService.create(admin, getAgendaList(agenda));
    }

    private List<RegulAgenda> getAgendaList(RegulAgenda agenda) {
        List<RegulAgenda> list = new ArrayList<>();
        list.add(agenda);
        return list;
    }

    private Integer checkCreateApoHoofd(Admin admin, ApoBedragDTO bedragDto, String actor) {
        log.trace("checkCreateApoHoofd");
        // check&create hoofd
        // check&create lijn
        // create bedrag
        ApoLijnDTO lijnDto = bedragDto.getLijn();
        ApoHoofdDTO hoofdDto = lijnDto.getHoofd();

        List<ApoHoofd> hoofden =
                apoService.findByPersoonOpdrachtNummer(admin, hoofdDto.getOpdracht().getPersoon().getId(), hoofdDto.getOpdracht().getOpdrachtnr());
        ApoHoofd apoHoofd = null;
        for (ApoHoofd pojo : hoofden) {
            if (pojo.getBeginDatum().equals(hoofdDto.getBeginDatum())) {
                apoHoofd = pojo;
                break;
            }
        }

        if (apoHoofd == null) {

            TemporalContext.getInstance().setActualInterval(new Eternity());
            Opdracht opdracht =
                    opdrachtService.getByPersoonOpdrachtNr(admin, hoofdDto.getOpdracht().getPersoon().getId(), hoofdDto.getOpdracht().getOpdrachtnr());

            log.trace("opdrachtid : {}", opdracht.getId());

            TemporalContext.getInstance().clearActualInterval();

            AardKodeExtensie ake = aardKodeExtensieFacade.getById(lijnDto.getAardCodeExtensie().getId());

            LocalDateTime ingaveTijdstip = TemporalContext.getInstance().getWerkTijdstip();

            apoHoofd = new ApoHoofdPO();
            apoHoofd.setOpdracht(opdracht);
            apoHoofd.setBeginDatum(hoofdDto.getBeginDatum());
            apoHoofd.setEindDatum(hoofdDto.getBeginDatum().dayOfMonth().withMaximumValue());
            apoHoofd.setBron(ApoHoofdBron.GEBRUIKER);
            apoHoofd.setIngaveTijdstip(ingaveTijdstip);
            apoHoofd.setRegulTijdstip(null);
            apoHoofd.setActor(actor);

            ApoLijn apoLijn = new ApoLijnPO();
            apoLijn.setAardKodeExtensie(ake);
            apoLijn.setApoHoofd(apoHoofd);
            apoLijn.setRegimeBv(LnedefRegBv.getById(lijnDto.getRegimeBv().getId()));
            apoLijn.setIngaveTijdstip(ingaveTijdstip);
            apoLijn.setRegulTijdstip(null);
            apoLijn.setActor(actor);

            ApoBedrag apoBedrag = new ApoBedragPO();
            apoBedrag.setApoLijn(apoLijn);
            apoBedrag.setBedrag(new Money(bedragDto.getBedrag()));
            apoBedrag.setBedragType(RekenBedragType.getById(bedragDto.getBedragType().getId()));
            apoBedrag.setIngaveTijdstip(ingaveTijdstip);
            apoBedrag.setRegulTijdstip(null);
            apoBedrag.setActor(actor);

            Set<ApoBedrag> apoBedragen = new HashSet<>();
            apoBedragen.add(apoBedrag);
            apoLijn.setApoBedragen(apoBedragen);

            Set<ApoLijn> apoLijnen = new HashSet<>();
            apoLijnen.add(apoLijn);
            apoHoofd.setApoLijnen(apoLijnen);

            log.trace("Create ApoHoofd ...");

            apoHoofd = apoService.create(admin, apoHoofd);
        } else {
            checkCreateApoLijn(admin, apoHoofd.getId(), bedragDto, actor);
        }

        return apoHoofd.getId();
    }

    private void checkCreateApoLijn(Admin admin, Integer hoofdId, ApoBedragDTO dto, String actor) {
        log.trace("checkCreateApoLijn");
        ApoHoofd apoHoofd = apoService.getById(admin, hoofdId, "apoLijnen");

        AardKodeExtensie ake = aardKodeExtensieFacade.getById(dto.getLijn().getAardCodeExtensie().getId());

        // check&create lijn
        ApoLijn apoLijn = null;
        for (ApoLijn pojo : apoHoofd.getApoLijnen()) {
            if (pojo.getAardKodeExtensie().getId().compareTo(ake.getId()) == 0 && pojo.getRegulTijdstip() == null) {
                apoLijn = pojo;
                break;
            }
        }

        LocalDateTime ingaveTijdstip = TemporalContext.getInstance().getWerkTijdstip();

        if (apoLijn == null) {
            apoLijn = new ApoLijnPO();
            apoLijn.setAardKodeExtensie(ake);
            apoLijn.setApoHoofd(apoHoofd);
            apoLijn.setIngaveTijdstip(ingaveTijdstip);
            apoLijn.setRegulTijdstip(null);
            apoLijn.setRegimeBv(LnedefRegBv.getById(dto.getLijn().getRegimeBv().getId()));
            apoLijn.setActor(actor);
            apoLijn = apoService.createApoLijn(admin, apoLijn);
        }

        // create bedrag
        ApoBedrag pojo = new ApoBedragPO();
        pojo.setApoLijn(apoLijn);
        pojo.setBedrag(new Money(dto.getBedrag()));
        pojo.setBedragType(RekenBedragType.getById(dto.getBedragType().getId()));
        pojo.setIngaveTijdstip(ingaveTijdstip);
        pojo.setRegulTijdstip(null);
        pojo.setActor(actor);
        apoService.createBedrag(admin, pojo);
    }

    @Override
    @InitializeAdmin
    public List<ManueleTussenkomst> getManueleTussenkomsten(Admin admin, Werkgever werkgever, LocalDate datum) {

        LocalDate begindatum = datum.dayOfMonth().withMinimumValue();
        LocalDate einddatum = datum.dayOfMonth().withMaximumValue();

        TemporalContext.getInstance().setActualInterval(new Eternity());
        CriteriaBuilder cb = new CriteriaBuilder();
        cb.and("opdracht.werkgever", Criterium.EQ(werkgever));
        cb.and("datum", Criterium.GE(begindatum));
        cb.and("datum", Criterium.LE(einddatum));
        cb.and("regulTijdstip", Criterium.EQ(null));
        cb.fetch("opdracht{persoon{persoonSlices}, opdrachtSlices}, aardKodeExtensie");
        List<ManueleTussenkomst> result = mantusService.findByCriteria(admin, cb);
        TemporalContext.getInstance().clearActualInterval();
        return result;
    }

    @Override
    @InitializeAdmin
    public Boolean hasNotRekenResultaat(Admin admin, ManueleTussenkomstDTO dto) {
        // controleer of een rekenresultaat bestaat.
        LocalDate begin = dto.getDatum().withDayOfMonth(1);
        LocalDate end = begin.plusMonths(1).minusDays(1);

        List<RekenHoofd> pojos = new ArrayList<>();

        try {
            TemporalContext.getInstance().setActualInterval(new LocalDateInterval(begin, end));

            Integer opdrachtnr = dto.getOpdracht().getOpdrachtnr();
            Integer persoonId = dto.getOpdracht().getPersoon().getId();
            Opdracht opdracht = opdrachtService.getByPersoonOpdrachtNr(admin, persoonId, opdrachtnr);

            if (opdracht != null) {
                pojos = rekenResultatenService.findByOpdrachtenBegindatum(admin, Collections.singletonList(opdracht), begin);
            }
        } finally {
            TemporalContext.getInstance().clearActualInterval();
        }

        return pojos.isEmpty();
    }

    @Override
    @InitializeAdmin
    @Transactional
    public ManueleTussenkomst createUpdateManueleTussenkomst(Admin admin, ManueleTussenkomstDTO dto, String actor) {
        if (dto.getId() != null) {
            // update, delete old mantus and create a new one
            deleteManueleTussenkomst(admin, dto.getId());
        }

        return createManueleTussenkomst(admin, dto, actor);
    }

    @Override
    @InitializeAdmin
    @Transactional
    public void createRegulAgendaMantus(Admin admin, Integer mantusId) {
        ManueleTussenkomst pojo = mantusService.getById(admin, mantusId, "opdracht{opdrachtSlices, persoon,werkgever}");
        Opdracht opdracht = pojo.getOpdracht();
        Persoon persoon = opdracht.getPersoon();

        RegulAgenda agenda = new RegulAgendaPO();
        RegulAgendaPK pk = new RegulAgendaPK();
        pk.setBeginDatum(LocalDateUtil.getInstance().withStartOfMonth(pojo.getDatum()));
        pk.setEindDatum(LocalDateUtil.getInstance().withEndOfMonth(pojo.getDatum()));
        pk.setOpdrachtNummer(opdracht.getOpdrachtnr());
        pk.setPersoon(persoon);
        pk.setRegulStatus(Regulkode.WIJZ_MANUELE_TUSSENKOMSTEN.getCode());
        agenda.setId(pk);
        agenda.setWerkgever(opdracht.getWerkgever());
        agenda.setBron(BronAgenda.RM_INPUT);

        regulAgendaService.create(admin, getAgendaList(agenda));
    }

    private ManueleTussenkomst createManueleTussenkomst(Admin admin, ManueleTussenkomstDTO dto, String actor) {
        ManueleTussenkomst pojo = new ManueleTussenkomstPO();

        AardKodeExtensie ake = aardKodeExtensieFacade.getById(dto.getAardKodeExtensie().getId());

        TemporalContext.getInstance().setActualInterval(new Eternity());
        Integer opdrachtnr = dto.getOpdracht().getOpdrachtnr();
        Integer persoonId = dto.getOpdracht().getPersoon().getId();
        Opdracht opdracht = opdrachtService.getByPersoonOpdrachtNr(admin, persoonId, opdrachtnr);
        TemporalContext.getInstance().clearActualInterval();

        pojo.setVerantwoording(StringUtils.trimToEmpty(dto.getVerantwoording()));
        pojo.setAardKodeExtensie(ake);
        pojo.setBedrag(new Money(dto.getBedrag()));
        pojo.setBedragType(RekenBedragType.getById(dto.getBedragType().getId()));
        pojo.setBron(ManueleTussenkomstBron.GEBRUIKER);
        pojo.setDatum(dto.getDatum());
        pojo.setFunctie(ManueleTussenkomstFunctie.getById(dto.getFunctie().getId()));
        pojo.setOpdracht(opdracht);
        pojo.setRegimeBv(LnedefRegBv.getById(dto.getRegimeBv().getId()));
        pojo.setActor(actor);
        pojo = mantusService.create(admin, pojo);

        createRegulAgendaMantus(admin, pojo.getId());

        return pojo;
    }

    @Override
    @InitializeAdmin
    @Transactional
    public void deleteManueleTussenkomst(Admin admin, Integer id) {
        ManueleTussenkomst pojo = mantusService.getById(admin, id);

        createRegulAgendaMantus(admin, id);

        mantusService.delete(admin, pojo);
    }
}
